solution_code:
#include <iostream>

int main() {
    auto isPositive = [](int x) { return x > 0; };
    auto isNegative = [](int x) { return x < 0; };
    auto isZero     = [](int x) { return x == 0; };

    int n;
    std::cin >> n;

    int pos = 0, neg = 0, zero = 0;
    for (int i = 0; i < n; ++i) {
        int val;
        std::cin >> val;
        if (isPositive(val)) ++pos;
        else if (isNegative(val)) ++neg;
        else if (isZero(val)) ++zero;
    }

    std::cout << "Positive: " << pos  << "\n";
    std::cout << "Negative: " << neg  << "\n";
    std::cout << "Zero: "     << zero << "\n";
    return 0;
}

