solution_code:
#include <iostream>
#include <string>

int applyTwice(int (*f)(int), int val) {
    return f(f(val));
}

int main() {
    std::string op;
    int n;
    std::cin >> op >> n;

    int result = 0;
    if (op == "double")
        result = applyTwice([](int x) { return x * 2; }, n);
    else if (op == "increment")
        result = applyTwice([](int x) { return x + 1; }, n);

    std::cout << result << "\n";
    return 0;
}
